/**
 * Zod schemas for pi-speak configuration.
 *
 * Uses Zod for runtime validation and TypeScript inference.
 */

import { z } from "zod";
import { SCHEMA_URL } from "./constants";

// ŌöĆŌöĆŌöĆ Sub-schemas ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export const TTSConfigSchema = z.object({
  // https://docs.v8.unrealspeech.com/
  voiceId: z.string().default("Sierra"),
  bitrate: z.string().default("192k"),
  speed: z.number().min(-1).max(1).default(0),
  pitch: z.number().min(0.5).max(1.5).default(1.0),
  maxChunkChars: z.number().int().min(1).max(1000).default(900)
});

export const BehaviorConfigSchema = z.object({
  shortcut: z.string().default("alt+r"),
  pingEnabled: z.boolean().default(true),
  pingOnStartEnabled: z.boolean().default(false),
  fallbackPingText: z.string().default("Work finished.")
});

export const SummarizerConfigSchema = z.object({
  // https://openrouter.ai/models
  enabled: z.boolean().default(true),
  model: z.string().default("openai/gpt-oss-20b"),
  maxTokens: z.number().int().min(1).max(500).default(60),
  timeoutMs: z.number().int().min(1000).max(60000).default(5000),
  prompt: z
    .string()
    .default(
      "You write ultra-concise voice notifications. Always include the session name if given. Max 2 sentences. Be specific about what was done."
    )
});

export const DebugConfigSchema = z.object({
  enabled: z.boolean().default(true),
  logPath: z.string().default("~/.pi-speak-debug.log"),
  logMaxBytes: z
    .number()
    .int()
    .min(1024)
    .max(10 * 1024 * 1024)
    .default(2 * 1024 * 1024)
});

export const ApiConfigSchema = z.object({
  unrealSpeechKey: z.string().nullable().default(null),
  openRouterKey: z.string().nullable().default(null)
});

// ŌöĆŌöĆŌöĆ Main schema ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export { SCHEMA_URL } from "./constants";

export const SpeakConfigSchema = z.object({
  $schema: z.string().url().default(SCHEMA_URL),
  version: z.number().int().min(0).default(1),
  tts: TTSConfigSchema,
  behavior: BehaviorConfigSchema,
  summarizer: SummarizerConfigSchema,
  debug: DebugConfigSchema,
  api: ApiConfigSchema
});

export type SpeakConfig = z.infer<typeof SpeakConfigSchema>;

/**
 * Configuration migrations for pi-speak.
 *
 * Each migration transforms a config from version N to N+1.
 * On load, every config passes through the full chain from its current
 * version up to CURRENT_VERSION.
 */

import { SCHEMA_URL } from "./constants";
import { DEFAULT_CONFIG } from "./defaults";
import type { SpeakConfig } from "./schema";

type Migration = (cfg: Record<string, unknown>) => Record<string, unknown>;

/** v0 (flat) ŌåÆ v1 (nested schema) */
function migrateV0ToV1(raw: Record<string, unknown>): Record<string, unknown> {
  return {
    $schema: SCHEMA_URL,
    version: 1,
    tts: {
      voiceId: raw.voiceId ?? DEFAULT_CONFIG.tts.voiceId,
      bitrate: raw.bitrate ?? DEFAULT_CONFIG.tts.bitrate,
      speed: raw.speed ?? DEFAULT_CONFIG.tts.speed,
      pitch: raw.pitch ?? DEFAULT_CONFIG.tts.pitch,
      maxChunkChars: raw.maxChunkChars ?? DEFAULT_CONFIG.tts.maxChunkChars
    },
    behavior: {
      shortcut: raw.shortcut ?? DEFAULT_CONFIG.behavior.shortcut,
      pingEnabled: DEFAULT_CONFIG.behavior.pingEnabled,
      pingOnStartEnabled: DEFAULT_CONFIG.behavior.pingOnStartEnabled,
      fallbackPingText: DEFAULT_CONFIG.behavior.fallbackPingText
    },
    summarizer: {
      enabled: DEFAULT_CONFIG.summarizer.enabled,
      model: raw.summarizerModel ?? DEFAULT_CONFIG.summarizer.model,
      maxTokens: DEFAULT_CONFIG.summarizer.maxTokens,
      timeoutMs: DEFAULT_CONFIG.summarizer.timeoutMs,
      prompt: DEFAULT_CONFIG.summarizer.prompt
    },
    debug: {
      enabled: raw.debug ?? DEFAULT_CONFIG.debug.enabled,
      logPath: DEFAULT_CONFIG.debug.logPath,
      logMaxBytes: DEFAULT_CONFIG.debug.logMaxBytes
    },
    api: {
      unrealSpeechKey: DEFAULT_CONFIG.api.unrealSpeechKey,
      openRouterKey: DEFAULT_CONFIG.api.openRouterKey
    }
  };
}

/** v1 ŌåÆ v2 (add summarizer.prompt) */
function migrateV1ToV2(raw: Record<string, unknown>): Record<string, unknown> {
  const summarizer = (raw.summarizer ?? {}) as Record<string, unknown>;
  if (summarizer.prompt === undefined) {
    summarizer.prompt = DEFAULT_CONFIG.summarizer.prompt;
  }
  return { ...raw, version: 2, summarizer };
}

const migrations: Migration[] = [
  migrateV0ToV1, // index 0: runs for fromVersion === 0
  migrateV1ToV2 // index 1: runs for fromVersion === 1
];

export const CURRENT_VERSION = migrations.length;

/**
 * Migrate raw config to current schema version.
 * Applies each migration in sequence from fromVersion up to CURRENT_VERSION.
 */
export function migrate(raw: unknown, fromVersion: number): SpeakConfig {
  let cfg = raw as Record<string, unknown>;

  for (let i = fromVersion; i < migrations.length; i++) {
    cfg = migrations[i](cfg);
  }

  return cfg as SpeakConfig;
}

import { describe, expect, it } from "vitest";
import { DEFAULT_CONFIG } from "./defaults";
import { CURRENT_VERSION, migrate } from "./migrations";
import type { SpeakConfig } from "./schema";

// ŌöĆŌöĆŌöĆ Helpers ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

function v0Config(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return { ...overrides };
}

function v1Config(overrides: Partial<SpeakConfig> = {}): SpeakConfig {
  return {
    $schema: "https://example.com/schema",
    version: 1,
    tts: { ...DEFAULT_CONFIG.tts },
    behavior: { ...DEFAULT_CONFIG.behavior },
    summarizer: { ...DEFAULT_CONFIG.summarizer },
    debug: { ...DEFAULT_CONFIG.debug },
    api: { ...DEFAULT_CONFIG.api },
    ...overrides
  };
}

// ŌöĆŌöĆŌöĆ v0 ŌåÆ v1 ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

describe("migrateV0ToV1", () => {
  it("should flatten v0 flat config to v1 nested schema", () => {
    const v0 = v0Config({
      voiceId: "Scarlett",
      bitrate: "128k",
      speed: 0.5,
      pitch: 1.2,
      maxChunkChars: 800,
      shortcut: "cmd+r",
      debug: false,
      summarizerModel: "anthropic/claude-3"
    });

    const migrated = migrate(v0, 0);

    expect(migrated.version).toBe(2);
    expect(migrated.tts.voiceId).toBe("Scarlett");
    expect(migrated.tts.bitrate).toBe("128k");
    expect(migrated.tts.speed).toBe(0.5);
    expect(migrated.tts.pitch).toBe(1.2);
    expect(migrated.tts.maxChunkChars).toBe(800);
    expect(migrated.behavior.shortcut).toBe("cmd+r");
    expect(migrated.debug.enabled).toBe(false);
    expect(migrated.summarizer.model).toBe("anthropic/claude-3");
    expect(migrated.summarizer.prompt).toBe(DEFAULT_CONFIG.summarizer.prompt);
  });

  it("should use defaults for missing v0 fields", () => {
    const v0 = v0Config({ voiceId: "Scarlett" });

    const migrated = migrate(v0, 0);

    expect(migrated.tts.voiceId).toBe("Scarlett");
    expect(migrated.tts.bitrate).toBe(DEFAULT_CONFIG.tts.bitrate);
    expect(migrated.behavior.shortcut).toBe(DEFAULT_CONFIG.behavior.shortcut);
    expect(migrated.summarizer.model).toBe(DEFAULT_CONFIG.summarizer.model);
  });

  it("should handle empty v0 config", () => {
    const migrated = migrate(v0Config({}), 0);

    expect(migrated.tts.voiceId).toBe(DEFAULT_CONFIG.tts.voiceId);
  });
});

// ŌöĆŌöĆŌöĆ v1 ŌåÆ v2 ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

describe("migrateV1ToV2", () => {
  it("should add summarizer.prompt with default value", () => {
    // Simulate old v1 config before prompt field existed
    const v1: Record<string, unknown> = {
      version: 1,
      tts: DEFAULT_CONFIG.tts,
      behavior: DEFAULT_CONFIG.behavior,
      summarizer: {
        enabled: true,
        model: "openai/gpt-oss-20b",
        maxTokens: 60,
        timeoutMs: 5000
      },
      debug: DEFAULT_CONFIG.debug,
      api: DEFAULT_CONFIG.api
    };

    const migrated = migrate(v1, 1);

    expect(migrated.summarizer.prompt).toBe(DEFAULT_CONFIG.summarizer.prompt);
    expect(migrated.summarizer.model).toBe("openai/gpt-oss-20b");
  });

  it("should preserve existing custom prompt", () => {
    const customPrompt = "Be funny and brief.";
    const v1 = v1Config({
      summarizer: {
        enabled: true,
        model: "openai/gpt-oss-20b",
        maxTokens: 60,
        timeoutMs: 5000,
        prompt: customPrompt
      }
    });

    const migrated = migrate(v1 as unknown as Record<string, unknown>, 1);

    expect(migrated.summarizer.prompt).toBe(customPrompt);
  });
});

// ŌöĆŌöĆŌöĆ Chained migration ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

describe("chained migration (v0 ŌåÆ v2)", () => {
  it("should run full chain from v0 to current version", () => {
    const v0 = v0Config({
      voiceId: "Scarlett",
      summarizerModel: "anthropic/claude-3"
    });

    const migrated = migrate(v0, 0);

    expect(migrated.version).toBe(2);
    expect(migrated.tts.voiceId).toBe("Scarlett");
    expect(migrated.summarizer.model).toBe("anthropic/claude-3");
    expect(migrated.summarizer.prompt).toBe(DEFAULT_CONFIG.summarizer.prompt);
  });
});

// ŌöĆŌöĆŌöĆ CURRENT_VERSION ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

describe("CURRENT_VERSION", () => {
  it("should match migrations array length", () => {
    expect(CURRENT_VERSION).toBe(2);
  });
});

/**
 * Default configuration values for pi-speak.
 */

import type { SpeakConfig } from "./schema";

export const DEFAULT_CONFIG: SpeakConfig = {
