}

/**
 * Configuration constants for pi-speak.
 */

export const SCHEMA_URL = "https://raw.githubusercontent.com/nikbrunner/pi-speak/main/src/config/schema.json";

export const CONFIG_DIR = `${process.env.HOME}/.config/pi-speak`;
export const CONFIG_PATH = `${CONFIG_DIR}/config.json`;

