/**
 * Zod schemas for pi-speak configuration.
 *
 * Uses Zod for runtime validation and TypeScript inference.
 */

import { z } from "zod";
import { SCHEMA_URL } from "./constants.js";

// ŌöĆŌöĆŌöĆ Sub-schemas ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export const TTSConfigSchema = z.object({
  // https://docs.v8.unrealspeech.com/
  voiceId: z.string().default("Sierra"),
  bitrate: z.string().default("192k"),
  speed: z.number().min(-1).max(1).default(0),
  pitch: z.number().min(0.5).max(1.5).default(1.0),
  maxChunkChars: z.number().int().min(1).max(1000).default(900)
});

export const BehaviorConfigSchema = z.object({
  shortcut: z.string().default("alt+r"),
  pingEnabled: z.boolean().default(true),
  pingOnStartEnabled: z.boolean().default(false),
  fallbackPingText: z.string().default("Work finished.")
});

export const SummarizerConfigSchema = z.object({
  // https://openrouter.ai/models
  enabled: z.boolean().default(true),
  model: z.string().default("openai/gpt-oss-20b"),
  maxTokens: z.number().int().min(1).max(500).default(60),
  timeoutMs: z.number().int().min(1000).max(60000).default(5000)
});

export const DebugConfigSchema = z.object({
  enabled: z.boolean().default(true),
  logPath: z.string().default("~/.pi-speak-debug.log"),
  logMaxBytes: z
    .number()
    .int()
    .min(1024)
    .max(10 * 1024 * 1024)
    .default(2 * 1024 * 1024)
});

export const ApiConfigSchema = z.object({
  unrealSpeechKey: z.string().nullable().default(null),
  openRouterKey: z.string().nullable().default(null)
});

// ŌöĆŌöĆŌöĆ Main schema ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export { SCHEMA_URL } from "./constants.js";

export const SpeakConfigSchema = z.object({
  $schema: z.string().url().default(SCHEMA_URL),
  version: z.number().int().min(0).default(1),
  tts: TTSConfigSchema,
  behavior: BehaviorConfigSchema,
  summarizer: SummarizerConfigSchema,
  debug: DebugConfigSchema,
  api: ApiConfigSchema
});

export type SpeakConfig = z.infer<typeof SpeakConfigSchema>;

/**
 * Default configuration values for pi-speak.
 */

import type { SpeakConfig } from "./schema.js";

export const DEFAULT_CONFIG: SpeakConfig = {
  $schema: "https://raw.githubusercontent.com/nikbrunner/pi-speak/main/src/config/schema.json",
  version: 1,
  tts: {
    voiceId: "Sierra",
    bitrate: "192k",
    speed: 0,
    pitch: 1.0,
    maxChunkChars: 900
  },
  behavior: {
    shortcut: "alt+r",
    pingEnabled: true,
    pingOnStartEnabled: false,
    fallbackPingText: "Work finished."
  },
  summarizer: {
    enabled: true,
    model: "openai/gpt-oss-20b",
    maxTokens: 60,
    timeoutMs: 5000
  },
  debug: {
    enabled: true,
    logPath: "~/.pi-speak-debug.log",
    logMaxBytes: 2 * 1024 * 1024
  },
  api: {
    unrealSpeechKey: null,
    openRouterKey: null
  }
};

/**
 * Configuration for pi-speak extension.
 *
 * Reads from ~/.config/pi-speak/config.json, with sensible defaults.
 * Environment variables override file config.
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";
import { debug } from "./debug.js";

// ŌöĆŌöĆŌöĆ Types ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export interface SpeakConfig {
  /** Unreal Speech voice ID. Default: "Sierra" */
  voiceId: string;
  /** Audio bitrate. Default: "192k" */
  bitrate: string;
  /** Speech speed. -1.0 to 1.0. Default: 0 */
  speed: number;
  /** Speech pitch. 0.5 to 1.5. Default: 1.0 */
  pitch: number;
  /** Max chars per TTS chunk (Unreal Speech limit is 1000). Default: 900 */
  maxChunkChars: number;
  /** Keyboard shortcut for replay/stop. Default: "alt+r" */
  shortcut: string;
  /** Enable debug logging to ~/.pi-speak-debug.log. Default: true */
  debug: boolean;
  /** OpenRouter model for summarizer. Default: "openai/gpt-oss-20b" */
  summarizerModel: string;
}

const DEFAULT_CONFIG: SpeakConfig = {
  voiceId: "Sierra",
  bitrate: "192k",
  speed: 0,
  pitch: 1.0,
  maxChunkChars: 900,
  shortcut: "alt+r",
  debug: true,
  summarizerModel: "openai/gpt-oss-20b"
};

// ŌöĆŌöĆŌöĆ File path ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

const CONFIG_DIR = join(homedir(), ".config", "pi-speak");
const CONFIG_PATH = join(CONFIG_DIR, "config.json");

// ŌöĆŌöĆŌöĆ Load ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export function loadConfig(): SpeakConfig {
  let fileConfig: Partial<SpeakConfig> = {};

  if (existsSync(CONFIG_PATH)) {
    try {
      const raw = readFileSync(CONFIG_PATH, "utf-8");
      fileConfig = JSON.parse(raw);
      debug(`loadConfig: loaded from ${CONFIG_PATH}`);
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      debug(`loadConfig: failed to parse ${CONFIG_PATH}: ${message}`);
    }
  } else {
    debug(`loadConfig: no config file at ${CONFIG_PATH}, using defaults`);
  }

  // Env overrides
  const envOverrides: Partial<SpeakConfig> = {};
  if (process.env.PI_SPEAK_VOICE) envOverrides.voiceId = process.env.PI_SPEAK_VOICE;
  if (process.env.PI_SPEAK_BITRATE) envOverrides.bitrate = process.env.PI_SPEAK_BITRATE;
  if (process.env.PI_SPEAK_SPEED) envOverrides.speed = parseFloat(process.env.PI_SPEAK_SPEED);
  if (process.env.PI_SPEAK_PITCH) envOverrides.pitch = parseFloat(process.env.PI_SPEAK_PITCH);
  if (process.env.PI_SPEAK_SHORTCUT) envOverrides.shortcut = process.env.PI_SPEAK_SHORTCUT;
  if (process.env.PI_SPEAK_DEBUG !== undefined) envOverrides.debug = process.env.PI_SPEAK_DEBUG !== "0";
  if (process.env.PI_SPEAK_SUMMARIZER_MODEL) envOverrides.summarizerModel = process.env.PI_SPEAK_SUMMARIZER_MODEL;

  const config = { ...DEFAULT_CONFIG, ...fileConfig, ...envOverrides };
  debug(
    `loadConfig: voiceId=${config.voiceId} bitrate=${config.bitrate} speed=${config.speed} pitch=${config.pitch} shortcut=${config.shortcut}`
  );

  return config;
}

// ŌöĆŌöĆŌöĆ Init (create default config if missing) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export function initConfig(): void {
  if (existsSync(CONFIG_PATH)) return;

  try {
    mkdirSync(CONFIG_DIR, { recursive: true });
    writeFileSync(CONFIG_PATH, JSON.stringify(DEFAULT_CONFIG, null, 2) + "\n");
    debug(`initConfig: created default config at ${CONFIG_PATH}`);
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    debug(`initConfig: failed to create ${CONFIG_PATH}: ${message}`);
  }
}

/**
 * Configuration migrations for pi-speak.
 *
 * Handles upgrades from older config versions to the current schema.
 */

import { SCHEMA_URL } from "./constants.js";
import { DEFAULT_CONFIG } from "./defaults.js";
import type { SpeakConfig } from "./schema.js";

// ŌöĆŌöĆŌöĆ Types ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

interface LegacyConfigV0 {
  voiceId?: string;
  bitrate?: string;
  speed?: number;
  pitch?: number;
  maxChunkChars?: number;
  shortcut?: string;
  debug?: boolean;
  summarizerModel?: string;
}

// ŌöĆŌöĆŌöĆ Migrations ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

/**
 * Migrate v0 (flat) config to v1 (nested) schema.
 */
function migrateV0ToV1(raw: LegacyConfigV0): SpeakConfig {
  return {
    $schema: SCHEMA_URL,
    version: 1,
    tts: {
      voiceId: raw.voiceId ?? DEFAULT_CONFIG.tts.voiceId,
      bitrate: raw.bitrate ?? DEFAULT_CONFIG.tts.bitrate,
      speed: raw.speed ?? DEFAULT_CONFIG.tts.speed,
      pitch: raw.pitch ?? DEFAULT_CONFIG.tts.pitch,
      maxChunkChars: raw.maxChunkChars ?? DEFAULT_CONFIG.tts.maxChunkChars
    },
    behavior: {
      shortcut: raw.shortcut ?? DEFAULT_CONFIG.behavior.shortcut,
      pingEnabled: DEFAULT_CONFIG.behavior.pingEnabled,
      pingOnStartEnabled: DEFAULT_CONFIG.behavior.pingOnStartEnabled,
      fallbackPingText: DEFAULT_CONFIG.behavior.fallbackPingText
    },
    summarizer: {
      enabled: DEFAULT_CONFIG.summarizer.enabled,
      model: raw.summarizerModel ?? DEFAULT_CONFIG.summarizer.model,
      maxTokens: DEFAULT_CONFIG.summarizer.maxTokens,
      timeoutMs: DEFAULT_CONFIG.summarizer.timeoutMs
    },
    debug: {
      enabled: raw.debug ?? DEFAULT_CONFIG.debug.enabled,
      logPath: DEFAULT_CONFIG.debug.logPath,
      logMaxBytes: DEFAULT_CONFIG.debug.logMaxBytes
    },
    api: {
      unrealSpeechKey: DEFAULT_CONFIG.api.unrealSpeechKey,
      openRouterKey: DEFAULT_CONFIG.api.openRouterKey
    }
  };
}

// ŌöĆŌöĆŌöĆ Export migration function ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export const CURRENT_VERSION = 1;

/**
 * Migrate raw config to current schema version.
 */
export function migrate(raw: unknown, fromVersion: number): SpeakConfig {
  const cfg = raw as Record<string, unknown>;

  if (fromVersion < 1) {
    return migrateV0ToV1(cfg as LegacyConfigV0);
  }

  // Future migrations:
  // if (fromVersion < 2) { ... }

  return cfg as SpeakConfig;
}

