/**
 * Zod schemas for pi-speak configuration v0.
 *
 * Flat key structure (no nesting, no version field, no api section).
 * Based on initial commit e471078d:src/config.ts.
 * Env var overrides existed but are omitted (removed in d2bbad31).
 */

import { z } from "zod";

const V0_DEFAULTS = {
  voiceId: "Sierra",
  bitrate: "192k",
  speed: 0,
  pitch: 1.0,
  maxChunkChars: 900,
  shortcut: "alt+r",
  debug: true,
  summarizerModel: "openai/gpt-oss-20b"
} as const;

export const V0Schema = z.object({
  voiceId: z.string().default(V0_DEFAULTS.voiceId),
  bitrate: z.string().default(V0_DEFAULTS.bitrate),
  speed: z.number().min(-1).max(1).default(V0_DEFAULTS.speed),
  pitch: z.number().min(0.5).max(1.5).default(V0_DEFAULTS.pitch),
  maxChunkChars: z.number().int().min(1).max(1000).default(V0_DEFAULTS.maxChunkChars),
  shortcut: z.string().default(V0_DEFAULTS.shortcut),
  debug: z.boolean().default(V0_DEFAULTS.debug),
  summarizerModel: z.string().default(V0_DEFAULTS.summarizerModel)
});

export type V0Config = z.infer<typeof V0Schema>;

/**
 * Zod schemas for pi-speak configuration v1 (nested schema, no summarizer.prompt).
 *
 * Fully independent ŌĆö does not import from v0.
 */

import { z } from "zod";

import { SCHEMA_URL } from "../../constants";

const V1_DEFAULTS = {
  // TTS
  voiceId: "Sierra",
  bitrate: "192k",
  speed: 0,
  pitch: 1.0,
  maxChunkChars: 900,
  // Behavior
  shortcut: "alt+r",
  pingEnabled: true,
  pingOnStartEnabled: false,
  fallbackPingText: "Work finished.",
  // Summarizer
  summarizerEnabled: true,
  summarizerModel: "google/gemini-2.5-flash-lite",
  summarizerMaxTokens: 100,
  summarizerTimeoutMs: 5000,
  // Debug
  debugEnabled: true,
