You can use `.prefault` funtion in Zod

Link to the Prefaults documentation

```
const schema = z.object({
  a: z.number().optional().default(1),
  b: z.number().optional().default(2),
  c: z.object({
    c1: z.number().optional().default(3),
    c2: z.number().optional().default(4),
    c3: z.object({
      x: z.number().optional().default(1),
      y: z.number().optional().default(2),
      z: z.number().optional().default(3)
    }).prefault({})
  }).prefault({})
}).prefault({});

// Usage:

const parsed = schema.parse(undefined);
console.log(parsed); // { a: 1, b: 2, c: { c1: 3, c2: 4, c3: { x: 1, y: 2, z: 3 } } }
