/**
 * Zod schemas for pi-speak configuration v1 (nested schema, no summarizer.prompt).
 *
 * Fully independent ŌĆö does not import from v0.
 */

import { z } from "zod";

import { SCHEMA_URL } from "../../constants";

export const TTS_DEFAULTS = {
  voiceId: "Sierra",
  bitrate: "192k",
  speed: 0,
  pitch: 1.0,
  maxChunkChars: 900
};

export const BEHAVIOR_DEFAULTS = {
  shortcut: "alt+r",
  pingEnabled: true,
  pingOnStartEnabled: false,
  fallbackPingText: "Work finished."
};

export const SUMMARIZER_DEFAULTS = {
  enabled: true,
  model: "google/gemini-2.5-flash-lite",
  maxTokens: 100,
  timeoutMs: 5000
};

export const DEBUG_DEFAULTS = {
  enabled: true,
  logPath: "~/.pi-speak-debug.log",
  logMaxBytes: 2 * 1024 * 1024
};

export const API_DEFAULTS = {
  unrealSpeechKey: null as string | null,
  openRouterKey: null as string | null
};

// ŌöĆŌöĆŌöĆ Sub-schemas ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export const TTSSchema = z.object({
  voiceId: z.string().default(TTS_DEFAULTS.voiceId),
  bitrate: z.string().default(TTS_DEFAULTS.bitrate),
  speed: z.number().min(-1).max(1).default(TTS_DEFAULTS.speed),
  pitch: z.number().min(0.5).max(1.5).default(TTS_DEFAULTS.pitch),
  maxChunkChars: z.number().int().min(1).max(1000).default(TTS_DEFAULTS.maxChunkChars)
});

export const BehaviorSchema = z.object({
  shortcut: z.string().default(BEHAVIOR_DEFAULTS.shortcut),
  pingEnabled: z.boolean().default(BEHAVIOR_DEFAULTS.pingEnabled),
  pingOnStartEnabled: z.boolean().default(BEHAVIOR_DEFAULTS.pingOnStartEnabled),
  fallbackPingText: z.string().default(BEHAVIOR_DEFAULTS.fallbackPingText)
});

export const SummarizerSchema = z.object({
  enabled: z.boolean().default(SUMMARIZER_DEFAULTS.enabled),
  model: z.string().default(SUMMARIZER_DEFAULTS.model),
  maxTokens: z.number().int().min(1).max(500).default(SUMMARIZER_DEFAULTS.maxTokens),
  timeoutMs: z.number().int().min(1000).max(60000).default(SUMMARIZER_DEFAULTS.timeoutMs)
});

export const DebugSchema = z.object({
  enabled: z.boolean().default(DEBUG_DEFAULTS.enabled),
  logPath: z.string().default(DEBUG_DEFAULTS.logPath),
  logMaxBytes: z.number().int().min(1024).max(10 * 1024 * 1024).default(DEBUG_DEFAULTS.logMaxBytes)
});

export const ApiSchema = z.object({
  unrealSpeechKey: z.string().nullable().default(API_DEFAULTS.unrealSpeechKey),
