import { z } from "zod";

export const TTS_DEFAULTS = {
  voiceId: "Sierra",
  bitrate: "192k",
  speed: 0,
  pitch: 1.0,
  maxChunkChars: 900
};

export const BEHAVIOR_DEFAULTS = {
  shortcut: "alt+r"
};

export const DEBUG_DEFAULTS = {
  debug: true
};

export const SUMMARIZER_MODEL_DEFAULTS = {
  summarizerModel: "openai/gpt-oss-20b"
};

export const V0Schema = z.object({
  voiceId: z.string().default(TTS_DEFAULTS.voiceId),
  bitrate: z.string().default(TTS_DEFAULTS.bitrate),
  speed: z.number().min(-1).max(1).default(TTS_DEFAULTS.speed),
  pitch: z.number().min(0.5).max(1.5).default(TTS_DEFAULTS.pitch),
  maxChunkChars: z
    .number()
    .int()
    .min(1)
    .max(1000)
    .default(TTS_DEFAULTS.maxChunkChars),
  shortcut: z.string().default(BEHAVIOR_DEFAULTS.shortcut),
  debug: z.boolean().default(DEBUG_DEFAULTS.debug),
  summarizerModel: z.string().default(SUMMARIZER_MODEL_DEFAULTS.summarizerModel)
});

export const V0_SCHEMA_DEFAULTS = V0Schema.parse({});

export type V0Config = z.infer<typeof V0Schema>;

